Code:
public int makeChocolate(int small, int big, int goal) {
    int bigCount = goal / 5;
    int remaining = goal % 5;
    if (bigCount > big) {
        bigCount = big;
        remaining = goal - bigCount * 5;
    }

    if (remaining > small) {
        return -1;
    } else {
        return remaining;
    }
}

